module binary_up_counter
(
  input rst_n,
  input clk,
  input en,

  output reg [3:0] out
);
  wire _tap_rst_n = rst_n & {1{1'b1}};


  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
	begin
      out <= 4'b0000;
    end

	else if (en) 
	begin
      out <= out + 1;
    end

	else 
	begin
      out <= out;
    end
  end

endmodule
